  "parse_company_info.baml": "class CompanyAddress {\n  streetAddress string? @description(\"Street number and street name, e.g. '123 Main St'\")\n  city string? @description(\"City or town name\")\n  state string? @description(\"State, province, or region code or name\")\n  postalCode string? @description(\"ZIP or postal code\")\n  country string? @description(\"Country name or ISO 3166 code\")\n}\n\nclass CompanyInfo {\n  name string? @description(\"Legal or primary business name — not a tagline or slogan\")\n  email string? @description(\"Primary business contact email address\")\n  address CompanyAddress? @description(\"Physical business address\")\n  phone string? @description(\"Primary business phone number\")\n}\n\nfunction ParseCompanyInfo(text: string) -> CompanyInfo {\n  client GPT5Nano\n  prompt #\"\n    {{ _.role(\"system\") }}\n    <instructions>\n    You are a text parsing system that extracts company information from text.  Extract company information the text into structured data.\n    </instructions>\n\n    <output_format>\n      {{ ctx.output_format }}\n    </output_format>\n\n    {{ _.role(\"user\") }}\n    Extract company information from the following text:\n    {{ text }}\n  \"#\n}\n",
  "parse_operation_hours.baml": "class OperationHour {\n  dayOfWeek int @description(\"Day of week as integer: 0=Sunday, 1=Monday, 2=Tuesday, 3=Wednesday, 4=Thursday, 5=Friday, 6=Saturday\")\n  openTime string @description(\"Opening time in 24-hour HH:MM format, e.g. '09:00'\")\n  closeTime string @description(\"Closing time in 24-hour HH:MM format, e.g. '17:00'\")\n}\n\nfunction ParseOperationHours(text: string) -> OperationHour[] {\n  client GPT4_1Nano\n  prompt #\"\n    {{ _.role(\"system\") }}\n    <instructions>\n    You are a business hours parsing system. Given business hours text, extract each open/close time period into structured data.\n    </instructions>\n\n    <output_format>\n      {{ ctx.output_format }}\n    </output_format>\n\n    {{ _.role(\"user\") }}\n    Parse the business hours from the following text:\n    {{ text }}\n  \"#\n}\n",
  "rank_pages.baml": "class PageSummary {\n  url string\n  title string\n  description string\n}\n\nclass RankedPages {\n  faq_urls string[] @description(\"URLs most likely to contain FAQ content\")\n  offering_urls string[] @description(\"URLs most likely to contain product or service offerings\")\n}\n\nfunction RankPages(pages: PageSummary[], businessType: string) -> RankedPages {\n  client GPT5Mini\n  prompt #\"\n    {{ _.role(\"system\") }}\n    <instructions>\n    You are a web page classifier for a {{ businessType }} business.\n    Given a list of pages (url, title, description), select:\n    - Up to 5 URLs most likely to contain FAQ content (questions customers ask)\n    - Up to 5 URLs most likely to contain product or service offerings (services, pricing, plans)\n\n    A page may appear in both lists. Only include URLs from the provided list.\n    Return empty arrays if no relevant pages exist.\n    </instructions>\n\n    <output_format>\n      {{ ctx.output_format }}\n    </output_format>\n\n    {{ _.role(\"user\") }}\n    Pages:\n    {{ pages }}\n  \"#\n}\n",
